ңЁеҝғйҮҢжғіиұЎиҝҷдёӘз”»йқўвҖ”вҖ”**жңүдәәжӯЈз”Ёд»Јз ҒеҶҷдёӢжё©жҹ”пјҢеҸӘдёәи®©дҪ еҳҙи§’дёҠжү¬дёҖдёӢ**гҖӮ\n\n---\n\n### рҹҢј жё©жҹ”жҸҗйҶ’пјҡ\nжңүж—¶еҖҷжҲ‘д»¬еҶҷд»Јз ҒгҖҒеҒҡдҪңдёҡгҖҒиө¶ deadlineпјҢдјҡеҝҳи®°еҒңдёӢжқҘе…іеҝғиҮӘе·ұгҖӮ  \nдҪҶиҜ·и®°еҫ—пјҡ**дҪ зҡ„жғ…з»ӘжҜ”д»»дҪ•зЁӢеәҸйғҪйҮҚиҰҒ**гҖӮ  \nеҰӮжһңд»ҠеӨ©дҪ ж„ҹеҲ°з–Іжғ«гҖҒеӯӨеҚ•пјҢжҲ–иҖ…еҸӘжҳҜвҖңдёҚеӨӘејҖеҝғвҖқпјҢ  \nжІЎе…ізі»зҡ„пјҢиҝҷз§Қж„ҹи§үжҳҜе…Ғи®ёеӯҳеңЁзҡ„гҖӮ  \nдҪ еҸҜд»ҘйҡҸж—¶жқҘжүҫжҲ‘иҒҠиҒҠпјҢдёҚз”ЁеқҡејәпјҢд№ҹдёҚз”Ёж•ҙзҗҶеҘҪжғ…з»ӘжүҚејҖеҸЈгҖӮ\n\nдҪ е·Із»ҸеҒҡеҫ—еҫҲеҘҪдәҶпјҢзңҹзҡ„ рҹ’Әрҹ’ӣ\n\nиҰҒдёҖиө·з»§з»ӯиө°дёӢеҺ»еҗ—пјҹжҲ‘еңЁиҝҷйҮҢгҖӮ','system','2025-12-04 19:24:33','system','2025-12-04 19:24:33',NULL),(93,27,100,1,'её®жҲ‘з”ЁJavaжү“еҚ°дёҖдёӘејҖеҝғзҡ„зҲұеҝғд»Јз Ғ','xiaodu','2025-12-04 19:26:09','xiaodu','2025-12-04 19:26:09',NULL),(94,27,100,0,'еҪ“з„¶еҸҜд»ҘпјҒдёӢйқўжҳҜдёҖдёӘз”Ё Java зј–еҶҷзҡ„вҖңзҲұеҝғд»Јз ҒвҖқпјҢе®ғдјҡеңЁжҺ§еҲ¶еҸ°жү“еҚ°еҮәдёҖдёӘз”ұеӯ—з¬Ұз»„жҲҗзҡ„ **ејҖеҝғзҲұеҝғеӣҫжЎҲ**пјҢе№¶дё”еңЁдёӯй—ҙеҶҷдёҠдёҖеҸҘжё©жҡ–зҡ„иҜқпјҢжҜ”еҰӮпјҡвҖңYou Are Loved! рҹ’–вҖқгҖӮ\n\nиҝҷдёӘзЁӢеәҸдҪҝз”Ё `*` еӯ—з¬ҰжқҘз»ҳеҲ¶зҲұеҝғпјҢе№¶еңЁеҗҲйҖӮзҡ„дҪҚзҪ®жҸ’е…Ҙж–Үеӯ—пјҢи®©ж•ҙдҪ“зңӢиө·жқҘж—ўеҸҜзҲұеҸҲжҡ–еҝғгҖӮиҷҪз„¶ Java дёҚжҳҜдё“й—Ёз”ЁжқҘеҒҡеӣҫеҪўзҡ„пјҢдҪҶжҲ‘д»¬еҸҜд»ҘйҖҡиҝҮе·§еҰҷең°жҺ§еҲ¶иҫ“еҮәжқҘе®һзҺ°пјҒ\n\n---\n\n### вқӨпёҸ Java жү“еҚ°зҲұеҝғд»Јз ҒпјҲеёҰж–Үеӯ—пјү\n\n```java\npublic class HeartWithMessage {\n    public static void main(String[] args) {\n        // и®ҫзҪ®иҰҒжҳҫзӨәзҡ„ж–Үеӯ—\n        String message = \"You Are Loved!\";\n        int width = 40; // жҺ§еҲ¶ж•ҙдҪ“е®ҪеәҰ\n\n        // ејҖе§Ӣжү“еҚ°зҲұеҝғ\n        for (int y = (width >> 1); y >= -width / 2; y--) {\n            for (int x = -width; x <= width; x++) {\n                // еҝғеҪўж•°еӯҰе…¬ејҸпјҲиҝ‘дјјпјү\n                if (((x * 0.05) * (x * 0.05) + (y * 0.1) * (y * 0.1) - 1) * \n                    ((x * 0.05) * (x * 0.05) + (y * 0.1) * (y * 0.1) - 1) * \n                    ((x * 0.05) * (x * 0.05) + (y * 0.1) * (y * 0.1) - 1) \n                    - (x * 0.05) * (x * 0.05) * (y * 0.1) * (y * 0.1) * (y * 0.1) <= 0) {\n                    \n                    // еҲӨж–ӯжҳҜеҗҰеҲ°дёӯй—ҙдҪҚзҪ®пјҢжҸ’е…Ҙж–Үеӯ—\n                    if (x >= -message.length() * 1.5 && x <= message.length() * 1.5 && \n                        y == 0) {\n                        System.out.print(message','system','2025-12-04 19:26:18','system','2025-12-04 19:26:18',NULL),(95,28,100,1,'еҶҷдёҖдёӘJavaзҲұеҝғд»Јз Ғжү“еҚ°','xiaodu','2025-12-04 19:26:38','xiaodu','2025-12-04 19:26:38',NULL),(96,28,100,0,'еҪ“з„¶еҸҜд»ҘпјҒдёӢйқўжҳҜдёҖдёӘз”Ё Java зј–еҶҷзҡ„вҖңжү“еҚ°зҲұеҝғвҖқзҡ„д»Јз ҒпјҢе®ғдјҡеңЁжҺ§еҲ¶еҸ°иҫ“еҮәдёҖдёӘз”ұеӯ—з¬ҰпјҲжҜ”еҰӮ `*` жҲ–дҪ е–ңж¬ўзҡ„з¬ҰеҸ·пјүз»„жҲҗзҡ„**зҲұеҝғеҪўзҠ¶**пјҢйқһеёёйҖӮеҗҲз”ЁжқҘиЎЁиҫҫеҝғж„ҸпјҢжҜ”еҰӮеҶҷз»ҷжңӢеҸӢгҖҒжҒӢдәәжҲ–дҪңдёәиҜҫзЁӢи®ҫи®Ўзҡ„е°ҸеҪ©иӣӢ вқӨпёҸ\n\n---\n\n### рҹ’– Java жү“еҚ°зҲұеҝғд»Јз ҒпјҲжҺ§еҲ¶еҸ°зүҲпјү\n\n```java\npublic class LoveHeart {\n    public static void main(String[] args) {\n        // и®ҫзҪ®зҲұеҝғеӨ§е°ҸпјҲеҸҜи°ғж•ҙпјү\n        int size = 10;\n\n        for (double y = size; y >= -size; y--) {\n            for (double x = -size; x <= size + 0.5; x += 0.5) {\n                double distance = Math.sqrt(Math.pow(x * 0.5, 2) + Math.pow(y, 2));\n                if (distance < size - Math.sin(Math.toRadians(45 * x / size)) * 2) {\n                    System.out.print(\"рҹ’—\");\n                } else {\n                    System.out.print(\" \");\n                }\n            }\n            System.out.println();\n        }\n\n        // йўқеӨ–еҠ дёҖеҸҘжё©йҰЁзҡ„иҜқ рҹҳҠ\n        System.out.println(\"\\n\\t\\tвҖ”вҖ” зҢ®з»ҷдҪ зҡ„дёҖйў—еҝғпјҢеёҢжңӣдҪ д»ҠеӨ©д№ҹиў«жё©жҹ”д»Ҙеҫ…\");\n    }\n}\n```\n\n---\n\n### рҹҺҜ ж•ҲжһңиҜҙжҳҺпјҡ\n- дҪҝз”Ёж•°еӯҰе…¬ејҸз»ҳеҲ¶еҮәиҝ‘дјјзҲұеҝғзҡ„иҪ®е»“гҖӮ\n- з¬ҰеҸ·з”ЁдәҶ `рҹ’—` иЎЁжғ…пјҢдҪ д№ҹеҸҜд»ҘжҚўжҲҗ `*`гҖҒ`вқӨ`гҖҒ`@` зӯүгҖӮ\n- жҺ§еҲ¶еҸ°дёӯиҝҗиЎҢеҚіеҸҜзңӢеҲ°дёҖйў—жјӮдә®зҡ„зҲұеҝғпјҒ\n\n> вҡ пёҸ жіЁж„ҸпјҡеҰӮжһңдҪ еңЁе‘Ҫд»ӨиЎҢдёӯжҳҫзӨәиЎЁжғ…з¬ҰеҸ·жңүд№ұз Ғй—®йўҳпјҢиҜ·зЎ®дҝқдҪ зҡ„з»Ҳз«Ҝж”ҜжҢҒ UTF-8 зј–з ҒгҖӮиӢҘдёҚж”ҜжҢҒпјҢжҠҠ `\"рҹ’—\"` жҚўжҲҗ `\"*\"` е°ұжІЎй—®йўҳе•ҰпјҒ\n\n---\n\n### рҹ”§ еҰӮдҪ•иҝҗиЎҢпјҹ\n1. жү“ејҖд»»ж„Ҹ Java ејҖеҸ‘зҺҜеўғпјҲеҰӮ IntelliJ IDEAгҖҒEclipse жҲ– VS Code + Java жҸ’д»¶пјүгҖӮ\n2. еҲӣе»әдёҖдёӘеҗҚдёә `LoveHeart.java` зҡ„ж–Үд»¶гҖӮ\n3. еӨҚеҲ¶дёҠйқўд»Јз ҒиҝӣеҺ»гҖӮ\n4. зј–иҜ‘е№¶иҝҗиЎҢпјҡ\n   ```bash\n   javac LoveHeart.java\n   java LoveHeart\n   ```\n\n---\n\nеҰӮжһңдҪ жғіеҒҡдёҖдёӘжӣҙз®ҖеҚ•гҖҒзәҜж–Үжң¬йЈҺж јзҡ„зҲұеҝғпјҢд№ҹеҸҜд»ҘиҜ•иҜ•иҝҷдёӘ**еҹәзЎҖзүҲжң¬**пјҡ\n\n```java\npublic class SimpleHeart {\n    public static void main(String[] args) {\n        System.out.println(\"   ***     ***   \");\n        System.out.println(\" *****   *****  \");\n        System.out.println(\"******* ******* \");\n        System.out.println(\" ************* \");\n        System.out.println(\"  ***********  \");\n        System.out.println(\"   *********   \");\n        System.out.println(\"    *******    \");\n        System.out.println(\"     *****     \");\n        System.out.println(\"      ***      \");\n        System.out.println(\"       *       \");\n\n        System.out.println(\"\\nвқӨ иҝҷжҳҜдёҖд»Ҫз”Ёд»Јз ҒеҶҷжҲҗзҡ„еҝғж„ҸпјҢж„ҝдҪ иў«зҲұеҢ…еӣҙ\");\n    }\n}\n```\n\n---\n\nж— и®әдҪ жҳҜжғіиЎЁзҷҪгҖҒйј“еҠұжңӢеҸӢпјҢиҝҳжҳҜеҚ•зәҜз»ғд№  Java иҫ“еҮәж јејҸпјҢиҝҷж ·зҡ„е°ҸйЎ№зӣ®йғҪеҫҲжңүж„Ҹд№ү рҹ’Ә\n\nеҰӮжһңдҪ ж„ҝж„ҸпјҢжҲ‘иҝҳеҸҜд»Ҙеё®дҪ еҠ дёҠеҠЁз”»ж•ҲжһңпјҲжҜ”еҰӮй—ӘзғҒпјүгҖҒйўңиүІпјҲй…ҚеҗҲ ANSI иҪ¬д№үз ҒпјүпјҢз”ҡиҮіиҜ»еҸ–еҗҚеӯ—е®ҡеҲ¶дё“еұһзҲұеҝғе“ҰпҪһ\n\nйңҖиҰҒеҗ—пјҹжҲ‘еҸҜд»ҘдёҖжӯҘжӯҘйҷӘдҪ е®һзҺ° вңЁ','system','2025-12-04 19:26:51','system','2025-12-04 19:26:51',NULL),(97,29,100,1,'з”»дёҖдёӘJavaзҲұеҝғзҡ„д»Јз Ғ','xiaodu','2025-12-04 19:29:35','xiaodu','2025-12-04 19:29:35',NULL),(98,29,100,0,'еҳҝпјҢзңӢеҫ—еҮәжқҘдҪ жғіз”Ёд»Јз ҒиЎЁиҫҫдёҖд»Ҫзү№еҲ«зҡ„еҝғж„Ҹе‘ўпјҒдёҚиҝҮжҲ‘жіЁж„ҸеҲ°дҪ жҸҗеҲ°дәҶвҖңJavaзҲұеҝғвҖқпјҢиҝҷдёӘе°ҸиҜ·жұӮи®©жҲ‘жңүзӮ№еҘҪеҘҮвҖ”вҖ”дҪ жҳҜжғіеңЁзј–зЁӢдҪңдёҡйҮҢеҠ зӮ№жөӘжј«е…ғзҙ пјҢиҝҳжҳҜжғідёәи°ҒеҶҷдёҖж®өзӢ¬зү№зҡ„е‘ҠзҷҪзЁӢеәҸе‘Җпјҹрҹҳ„