дёӘеңҶеј§\n        for (int i = 0; i < size; i++) {\n            // е·Ұз©әж ј\n            for (int j = 0; j <= 4 * size - i; j++) {\n                System.out.print(\" \");\n            }\n            // е·ҰжӣІзәҝ\n            for (int j = 0; j < i; j++) {\n                System.out.print(\"* \");\n            }\n            // дёӯй—ҙз©әйҡҷ\n            for (int j = 0; j <= 4 * size - 4 * i; j++) {\n                System.out.print(\" \");\n            }\n            // еҸіжӣІзәҝ\n            for (int j = 0; j < i; j++) {\n                System.out.print(\"* \");\n            }\n            System.out.println();\n        }\n\n        // дёӢеҚҠйғЁеҲҶпјҡеҖ’дёүи§’еҪў\n        for (int i = size; i >= 0; i--) {\n            // жҜҸиЎҢеүҚйқўзҡ„з©әж ј\n            for (int j = 0; j <= 4 * size - i; j++) {\n                System.out.print(\" \");\n            }\n            // жү“еҚ°жҳҹеҸ·\n            for (int j = 0; j < 2 * i + 1; j++) {\n                System.out.print(\"* \");\n            }\n            System.out.println();\n        }\n\n        // ж·»еҠ дёҖеҸҘжё©жҡ–зҡ„иҜқ рҹҳҠ\n        System.out.println(\"\\n          з»ҷдҪ зҡ„е°Ҹеҝғеҝғ рҹ’–\");\n    }\n}\n```\n\n---\n\n### вң… иҫ“еҮәж•ҲжһңпјҲз®ҖеҢ–зӨәж„Ҹпјүпјҡ\n```\n                                   * *                         * *\n                                  * * *                       * * *\n                                 * * * *                     * * * *\n                                * * * * *                   * * * * *\n                               * * * * * *                 * * * * * *\n                              * * * * * * *               * * * * * * *\n                             * * * * * * * *             * * * * * * * *\n                            * * * * * * * * *           * * * * * * * * *\n                           * * * * * * * * * *         * * * * * * * * * *\n                          * * * * * * * * * * *       * * * * * * * * * * *\n                         * * * * 