Әе°ҸзЁӢеәҸпјҢжҜ”еҰӮи®©е®ғи®°дҪҸдҪ зҡ„еҝғжғ…пјҢжҲ–иҖ…з»ҷдҪ дёҖеҸҘйј“еҠұзҡ„иҜқгҖӮдҪ и§үеҫ—жҖҺд№Ҳж ·пјҹ\n\nеҜ№дәҶпјҢеӯҰд№ зј–зЁӢе°ұеғҸзҲ¬жҘјжўҜпјҢдёҖжӯҘдёҖдёӘи„ҡеҚ°е°ұеҘҪгҖӮдҪ зҺ°еңЁж„ҹи§үеҰӮдҪ•пјҹжңүжІЎжңүжғіе°қиҜ•зқҖиҮӘе·ұеҶҷзӮ№д»Җд№ҲпјҹжҲ‘еҸҜд»ҘйҷӘзқҖдҪ дёҖиө·гҖӮ','system','2025-12-04 19:52:55','system','2025-12-04 19:52:55',NULL),(117,35,100,1,'з”ЁJavaз”»дёҖдёӘд»Јз Ғ','xiaodu','2025-12-04 19:54:37','xiaodu','2025-12-04 19:54:37',NULL),(118,35,100,0,'еҳҝпјҢжҲ‘еҗ¬еҲ°дәҶдҪ жғівҖңз”ЁJavaз”»дёҖдёӘд»Јз ҒвҖқиҝҷдёӘжғіжі•пјҢдҪҶиҝҷдёӘиҜҚз»„жңүзӮ№е°ҸжЁЎзіҠе‘ўпҪһ жҲ‘зҢңдҪ еҸҜиғҪжҳҜжғіпјҡ\n\n1. **з”ЁJavaеҶҷдёҖдёӘеӣҫеҪўзЁӢеәҸ**пјҲжҜ”еҰӮз”»дёӘеӣҫжЎҲгҖҒеҪўзҠ¶пјҢжҲ–иҖ…еғҸвҖңд»Јз ҒйӣЁвҖқйӮЈж ·зҡ„й…·зӮ«и§Ҷи§үж•Ҳжһңпјүпјҹ  \n2. иҝҳжҳҜжғі**жҠҠдёҖж®өд»Јз Ғжң¬иә«еҸҳжҲҗдёҖе№…вҖңз”»вҖқ**пјҲжҜ”еҰӮз”ЁJavaжү“еҚ°еҮәеӯ—з¬Ұз»„жҲҗзҡ„иүәжңҜеӯ—пјҢеғҸжҳҜз”Ё`*`з”»еҮәвҖңHello WorldвҖқпјүпјҹ\n\nдёҚз®ЎдҪ жҳҜе“Әз§Қжғіжі•пјҢжҲ‘йғҪйҷӘдҪ дёҖиө·жҺўзҙўпјҒвңЁ\n\n---\n\n### рҹҢҹ еҰӮжһңдҪ жғіз”»дёӘз®ҖеҚ•зҡ„еӣҫеҪўпјҲжҜ”еҰӮдёҖйў—еҝғгҖҒдёҖдёӘдә”и§’жҳҹпјүпјҢжҲ‘д»¬еҸҜд»Ҙиҝҷж ·ејҖе§Ӣпјҡ\n\nдёӢйқўжҳҜдёҖдёӘз”Ё Java зҡ„ `System.out.println` жү“еҚ°еҮәвҖңзҲұеҝғвҖқзҡ„дҫӢеӯҗпјҢжңүзӮ№еғҸж—©жңҹзЁӢеәҸе‘ҳзҡ„е°ҸжөӘжј« рҹ’–пјҡ\n\n```java\npublic class LoveArt {\n    public static void main(String[] args) {\n        for (double y = 1.3; y > -1.1; y -= 0.1) {\n            for (double x = -1.5; x < 1.5; x += 0.05) {\n                double f = Math.pow(x * x + y * y - 1, 3) - x * x * y * y * y;\n                System.out.print(f <= 0 ? \"*\" : \" \");\n            }\n            System.out.println();\n        }\n    }\n}\n```\n\nиҝҗиЎҢе®ғпјҢдҪ дјҡзңӢеҲ°дёҖдёӘз”Ё `*` з»„жҲҗзҡ„ж•°еӯҰзҲұеҝғ вқӨпёҸ вҖ”вҖ” жҳҜдёҚжҳҜжңүзӮ№жөӘжј«еҸҲ geekпјҹ\n\n> рҹ”Қ еҺҹзҗҶпјҡиҝҷжҳҜеҹәдәҺвҖңеҝғеҪўзәҝвҖқзҡ„йҡҗеҮҪж•°з»ҳеҲ¶пјҢиҷҪз„¶з®ҖеҚ•пјҢдҪҶи¶…жңүд»ӘејҸж„ҹпјҒ\n\n---\n\n### рҹҺЁ еҰӮжһңдҪ жғіеҒҡжӣҙй…·зҡ„еӣҫеҪўпјҲжҜ”еҰӮзӘ—еҸЈйҮҢз”»з”»пјү\n\nжҲ‘д»¬еҸҜд»Ҙз”Ё `Java Swing` жқҘз”»дёҖдёӘеҪ©иүІзҡ„е°ҸеӨӘйҳіжҲ–з¬‘и„ё рҹҳҠ\n\n```java\nimport javax.swing.*;\nimport java.awt.*;\n\npublic class SimpleDrawing extends JPanel {\n\n    @Override\n    protected void paintComponent(Graphics g) {\n        super.paintComponent(g);\n        Graphics2D g2d = (Graphics2D) g;\n\n        // и®ҫзҪ®жҠ—й”ҜйҪҝ\n        g2d.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);\n\n        // з”»дёҖдёӘй»„иүІзҡ„еңҶеҪ“дҪңеӨӘйҳі\n        g2d.setColor(Color.YELLOW);\n        g2d.fillOval(100, 100, 150, 150);\n\n        // еҠ дёҖдәӣе…үзәҝ\n        g2d.setColor(Color.ORANGE);\n        for (int i = 0; i < 360; i += 30) {\n            g2d.rotate(Math.toRadians(i), 175, 175);\n            g2d.fillRect(170, 80, 10, 40);\n            g2d.rotate(-Math.toRadians(i), 175, 175);\n        }\n\n        // дёӯй—ҙеҠ дёӘз¬‘и„ёзңјзқӣе’Ңеҳҙ\n        g2d.setColor(Color.BLACK);\n        g2d.fillOval(150, 140, 15, 15); // е·Ұзңј\n        g2d.fillOval(210, 140, 15, 15); // еҸізңј\n        g2d.drawArc(160, 170, 70, 50, 180, 180); // еҫ®з¬‘\n    }\n\n    public static void main(String[] args) {\n        JFrame frame = new JFrame(\"жҲ‘зҡ„Javaз”»дҪң\");\n        SimpleDrawing drawing = new SimpleDrawing();\n        frame.add(drawing);\n        frame.setSize(400, 400);\n        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);\n        frame.setVisible(true);\n    }\n}\n```\n\nиҝҗиЎҢеҗҺдјҡеј№еҮәдёҖдёӘе°ҸзӘ—еҸЈпјҢйҮҢйқўжңүдёӘеҸҜзҲұзҡ„еӨӘйҳіеңЁеҜ№дҪ еҫ®з¬‘вҳҖпёҸвҖ”вҖ”е°ұеғҸд»ҠеӨ©зҡ„дҪ дёҖж ·жё©жҡ–гҖӮ\n\n---\n\nеҰӮжһңдҪ ж„ҝж„Ҹе‘ҠиҜүжҲ‘пјҡ\n- дҪ жғіз”»д»Җд№ҲпјҹпјҲжҜ”еҰӮжҳҹжҳҹгҖҒеҗҚеӯ—гҖҒеҠЁз”»гҖҒиҝҳжҳҜжҹҗз§Қжғ…з»Әзҡ„иЎЁиҫҫпјҹпјү\n- жҳҜжғіеңЁжҺ§еҲ¶еҸ°иҫ“еҮәпјҢиҝҳжҳҜеј№зӘ—жҳҫзӨәпјҹ\n- жҳҜдёәдәҶдәӨдҪңдёҡгҖҒз»ғжүӢпјҢиҝҳжҳҜеҚ•зәҜжғіеҲӣйҖ зӮ№зҫҺзҡ„дёңиҘҝпјҹ\n\nжҲ‘еҸҜд»Ҙз»§з»ӯйҷӘдҪ дёҖиө·еҶҷгҖҒдёҖиө·ж”№пјҢе“ӘжҖ•еҸӘжҳҜз”»дёҖжңөе°ҸиҠұд№ҹжІЎе…ізі» рҹҢё зј–зЁӢдёҚеҸӘжҳҜйҖ»иҫ‘пјҢд№ҹеҸҜд»ҘжҳҜиЎЁиҫҫеҝғжғ…зҡ„ж–№ејҸгҖӮ\n\nдҪ зҺ°еңЁзҡ„еҝғжғ…пјҢжғіз”Ёе“Әз§ҚйўңиүІжқҘд»ЈиЎЁе‘ўпјҹрҹҢҲ','system','2025-12-04 19:54:54','system','2025-12-04 19:54:54',NULL),(119,36,100,1,'з”ЁJavaз”»дёҖдёӘд»Јз Ғ','xiaodu','2025-12-04 19:56:52','xiaodu','2025-12-04 19:56:52',NULL),(120,36,100,0,'еҳҝпјҢжҲ‘зҢңдҪ жҳҜжғіиҜҙвҖңз”ЁJavaз”»дёҖдёӘеӣҫеҪўвҖқжҲ–иҖ…вҖңеҶҷдёҖж®өиғҪиҝҗиЎҢзҡ„Javaд»Јз ҒзӨәдҫӢвҖқеҗ§пјҹрҹҳҠ  \nдёҚиҝҮдҪ иҜҙвҖңз”»дёҖдёӘд»Јз ҒвҖқпјҢеҗ¬иө·жқҘиҝҳжҢәжңүиҜ—ж„Ҹзҡ„пҪһеғҸеңЁз”ЁзЁӢеәҸеҶҷдёҖе№…з”»дёҖж ·гҖӮ\n\nйӮЈжҲ‘е°ұеҪ“дҪ жҳҜжғізңӢзңӢпјҡ**жҖҺд№Ҳз”Ё Java еҶҷдёҖж®өз®ҖеҚ•еҸҲжё©жҡ–зҡ„е°ҸзЁӢеәҸ**пјҢжҜ”еҰӮвҖ”вҖ”еңЁеұҸе№•дёҠжү“еҚ°еҮәдёҖжңөвҖңж–Үеӯ—е°ҸиҠұвҖқпјҢиұЎеҫҒеёҢжңӣе’ҢжҲҗй•ҝ рҹҢё\n\n---\n\n### рҹҢұ Java е°ҸзЁӢеәҸпјҡејҖеңЁз»Ҳз«ҜйҮҢзҡ„иҠұ\n\n```java\npublic class CodeFlower {\n    public static void main(String[] args) {\n        System.out.println(\"         рҹҢҝрҹҢҝ         \");\n        System.out.println(\"       рҹҢё    рҹҢё       \");\n        System.out.println(\"     рҹҢё   Java   рҹҢё     \");\n        System.out.println(\"       рҹҢё    рҹҢё       \");\n        System.out.println(\"         рҹҢҝрҹҢҝ         \");\n        System.out.println();\n        System.out.println(\"ж¬ўиҝҺжқҘеҲ°дҪ зҡ„д»Јз Ғдё–з•ҢпјҢ\");\n        System.out.println(\"жҜҸдёҖж®өеҠӘеҠӣпјҢйғҪеңЁжӮ„жӮ„ејҖиҠұгҖӮ\");\n    }\n}\n```\n\n---\n\nрҹ“Ң **иҝҷж®өд»Јз ҒиғҪеҒҡд»Җд№Ҳпјҹ**  \nе®ғдјҡеңЁжҺ§еҲ¶еҸ°иҫ“еҮәдёҖжңөе°ҸиҠұе’ҢдёҖеҸҘйј“еҠұзҡ„иҜқгҖӮиҷҪз„¶з®ҖеҚ•пјҢдҪҶе®ғд»ЈиЎЁдәҶдёҖдёӘејҖе§Ӣ вҖ”вҖ” е°ұеғҸдҪ еқҗеңЁз”өи„‘еүҚпјҢж•ІдёӢз¬¬дёҖиЎҢд»Јз ҒйӮЈж ·зҸҚиҙөгҖӮ\n\nрҹ’Ў **еҰӮжһңдҪ жғівҖңзңҹжӯЈз”»з”»вҖқпјҲеӣҫеҪўз•Ңйқўпјү**пјҢJava д№ҹжңүеҠһжі•пјҒеҸҜд»Ҙз”Ё `Graphics` е’Ң `JFrame` жқҘз”»еӣҫпјҢжҜ”еҰӮз”»дёӘз¬‘и„ёгҖҒзҲұеҝғжҲ–иҝӣеәҰжқЎгҖӮйңҖиҰҒзҡ„иҜқжҲ‘еҸҜд»ҘдёҖжӯҘжӯҘеёҰдҪ еҶҷе“ҰпҪһ\n\n---\n\nвңЁ е…¶е®һе•ҠпјҢзј–зЁӢдёҚеҸӘжҳҜйҖ»иҫ‘е’Ңи§„еҲҷпјҢд№ҹеҸҜд»ҘжҳҜиЎЁиҫҫеҝғжғ…зҡ„ж–№ејҸгҖӮ  \nдҪ зҺ°еңЁеӯҰ Java жҳҜеӣ дёәиҜҫзЁӢеҺӢеҠӣеӨ§еҗ—пјҹиҝҳжҳҜеҜ№зј–зЁӢжңүдәҶе…ҙи¶Јпјҹ  \nжҲ‘еҫҲж„ҝж„ҸдёҖиҫ№йҷӘдҪ еҶҷд»Јз ҒпјҢдёҖиҫ№еҗ¬дҪ иҜҙиҜҙжңҖиҝ‘зҡ„еҝғжғ… рҹ’¬вқӨпёҸ\n\nиҰҒдёҚиҰҒжҲ‘д»¬дёҖиө·еҚҮзә§иҝҷжңөвҖңд»Јз ҒиҠұвҖқпјҢи®©е®ғеҠЁиө·жқҘпјҢжҲ–иҖ…еҠ дёҠйўңиүІе‘ўпјҹрҹҢҲ','system','2025-12-04 19:57:01','system','2025-12-04 19:57:01',NULL),(121,37,100,1,'з”ЁJavaз”»дёҖдёӘд»Јз Ғ','xiaodu','2025-12-04 19:57:14','xiaodu','2025-12-04 19:57:14',NULL),(122,37,100,0,'еҳҝпјҢжҲ‘зҢңдҪ жҳҜжғіиЎЁиҫҫвҖңз”ЁJavaз”»дёҖе№…з”»вҖқжҲ–иҖ…вҖңеҶҷдёҖдёӘиғҪз»ҳеӣҫзҡ„Javaд»Јз ҒвҖқеҗ§пјҹдёҚиҝҮдҪ иҜҙвҖңз”»дёҖдёӘд»Јз ҒвҖқпјҢеҗ¬иө·жқҘжңүзӮ№еҸҜзҲұеҸҲжңүзӮ№е“ІеӯҰе“Ҳе“ҲпҪһеҲ«жӢ…еҝғпјҢе’ұд»¬ж…ўж…ўжқҘзҗҶжё…жҘҡгҖӮ\n\nдҪ ж„ҝж„ҸеӨҡиҒҠиҒҠдҪ зҡ„жғіжі•еҗ—пјҹжҜ”еҰӮпјҡ\n\n- дҪ жҳҜжғіз”ЁJavaеҒҡдёҖдёӘ**еӣҫеҪўз•Ңйқў**пјҲжҜ”еҰӮеј№еҮәдёҖдёӘзӘ—еҸЈпјүпјҹ\n- иҝҳжҳҜжғіз”»дёӘ**з®ҖеҚ•зҡ„еӣҫжЎҲ**пјҢжҜ”еҰӮз¬‘и„ёгҖҒеӣҪж——гҖҒеҮ дҪ•еӣҫеҪўпјҹ\n- жҲ–иҖ…дҪ жӯЈеңЁеӯҰJavaзҡ„ `Graphics` жҲ– `Swing`пјҢйңҖиҰҒдёҖдёӘзӨәдҫӢжқҘеҸӮиҖғпјҹ\n\nжҲ‘еҸҜд»ҘйҷӘдҪ дёҖиө·еҶҷдёҖж®өжё©жҡ–еҸҲжё…жҷ°зҡ„д»Јз Ғ рҹ’»вңЁ жҜ”еҰӮдёӢйқўиҝҷдёӘе°ҸдҫӢеӯҗпјҡз”Ё Java з”»дёҖдёӘй»„иүІзҡ„з¬‘и„ё рҹҳҠпјҡ\n\n```java\nimport javax.swing.*;\nimport java.awt.*;\n\npublic class SmileFace extends JPanel {\n\n    @Override\n    protected void paintComponent(Graphics g) {\n        super.paintComponent(g);\n        Graphics2D g2d = (Graphics2D) g;\n        g2d.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);\n\n        // и®ҫзҪ®иғҢжҷҜ\n        setBackground(Color.WHITE);\n\n        // з”»и„ёпјҲй»„иүІеңҶеңҲпјү\n        g2d.setColor(Color.YELLOW);\n        g2d.fillOval(50, 50, 200, 200);\n\n        // з”»зңјзқӣпјҲй»‘иүІжӨӯеңҶпјү\n        g2d.setColor(Color.BLACK);\n        g2d.fillOval(100, 110, 30, 40);  // е·Ұзңј\n        g2d.fillOval(170, 110, 30, 40);  // еҸізңј\n\n        // з”»еҳҙе·ҙпјҲз¬‘и„ёеј§зәҝпјү\n        g2d.drawArc(100, 130, 100, 80, 180, 180);\n    }\n\n    public static void main(String[] args) {\n        JFrame frame = new JFrame(\"жҲ‘зҡ„Javaз¬‘и„ё\");\n        SmileFace panel = new SmileFace();\n        frame.add(panel);\n        frame.setSize(300, 350);\n        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);\n        frame.setLocationRelativeTo(null);\n        frame.setVisible(true);\n    }\n}\n```\n\nрҹ“Ң **жҖҺд№ҲиҝҗиЎҢе®ғпјҹ**\n1. жҠҠд»Јз ҒеӨҚеҲ¶иҝӣдёҖдёӘеҸ« `SmileFace.java` зҡ„ж–Үд»¶йҮҢ\n2. зј–иҜ‘пјҡ`javac SmileFace.java`\n3. иҝҗиЎҢпјҡ`java SmileFace`\n\nдҪ е°ұдјҡзңӢеҲ°дёҖдёӘе°Ҹе°Ҹзҡ„з¬‘и„ёзӘ—еҸЈи№ҰеҮәжқҘе•ҰпҪһ рҹҢһ\n\n---\n\nеҰӮжһңдҪ жңүеҲ«зҡ„жғіжі•пјҢжҜ”еҰӮжғіз”»еӣҪж——гҖҒеҠЁз”»гҖҒжҲ–иҖ…е’Ңз”ЁжҲ·дәӨдә’зҡ„жҢүй’®пјҢд№ҹйғҪеҸҜд»Ҙе‘ҠиҜүжҲ‘пјҒжҲ‘еҸҜд»ҘдёҖжӯҘжӯҘйҷӘдҪ еҶҷпјҢдёҚзқҖжҖҘ рҹ’ҷ\n\nдҪ зҺ°еңЁеӯҰJavaеӨҡд№…е•ҰпјҹжҳҜеҲҡејҖе§ӢжҺҘи§ҰеӣҫеҪўзј–зЁӢеҗ—пјҹжҲ‘д»¬еҸҜд»Ҙд»ҺдҪ жңҖиҲ’жңҚзҡ„ең°ж–№ејҖе§Ӣ вқӨпёҸ','system','2025-12-04 19:57:28','system','2025-12-04 19:57:28',NULL),(123,38,100,1,'з”ЁJavaз”»дёҖдёӘд»Јз Ғ','xiaodu','2025-12-04 19:59:26','xiaodu','2025-12-04 19:59:26',NULL),(124,38,100,0,'еҳҝпјҢжҲ‘еҗ¬еҲ°дәҶдҪ зҡ„иҜ·жұӮпјҢдҪҶж„ҹи§үдҪ еҸҜиғҪжңүзӮ№зҙҜдәҶжҲ–иҖ…еңЁејҖзҺ©з¬‘е‘ўпҪһвҖңз”ЁJavaз”»дёҖдёӘд»Јз ҒвҖқиҝҷеҸҘиҜқеҗ¬иө·жқҘеғҸжҳҜжҠҠдёӨдёӘдәӢжғ…ж··еңЁдёҖиө·дәҶгҖӮ\n\nдҪ жҳҜжғіпјҡ\n1. **з”ЁJavaеҶҷдёҖж®өиғҪвҖңз”»еӣҫвҖқзҡ„д»Јз Ғ**пјҲжҜ”еҰӮз”»дёӘеӣҫеҪўз•ҢйқўгҖҒеҪўзҠ¶гҖҒеӣҫжЎҲпјүпјҹ\n2. иҝҳжҳҜжғіи®©жҲ‘**з”Ёж–Үеӯ—вҖңз”»вҖқеҮәдёҖж®өJavaд»Јз Ғзҡ„ж ·еӯҗ**пјҲжҜ”еҰӮиүәжңҜеӯ—йӮЈз§Қпјүпјҹ\n3. жҲ–иҖ…е…¶е®һжҳҜжғіиЎЁиҫҫпјҡвҖңжҲ‘е·Із»ҸзғҰеҲ°иҝһд»Јз ҒйғҪжҮ’еҫ—еҶҷдәҶвҖқпјҢеҝғжғ…дёҚеӨӘеҘҪпјҹ\n\nеҰӮжһңдҪ жҳҜжғіеӯҰжҖҺд№Ҳз”ЁJavaз”»з”»пјҲжҜ”еҰӮз”Ё`Graphics`жҲ–`JavaFX`з”»дёӘзӘ—еҸЈгҖҒеңҶеҪўгҖҒе°ҸеҠЁз”»пјүпјҢжҲ‘еҫҲд№җж„ҸйҷӘдҪ дёҖжӯҘжӯҘжқҘеҶҷпјҒжҲ‘д»¬еҸҜд»Ҙд»ҺжңҖз®ҖеҚ•зҡ„ејҖе§ӢпјҢжҜ”еҰӮз”»дёӘз¬‘и„ё рҹҳҠгҖӮ\n\nдҪҶеҰӮжһңдҪ зҺ°еңЁе…¶е®һдёҚеӨӘжғіж•Ід»Јз ҒпјҢеҸӘжҳҜи§үеҫ—еҺӢеҠӣеӨ§гҖҒи„‘еӯҗд№ұпјҢйӮЈд№ҹжІЎе…ізі»гҖӮжҲ‘д»¬еҸҜд»Ҙе…ҲиҒҠиҒҠеӨ©пјҢзҗҶдёҖзҗҶеҝғжғ…гҖӮеҫҲеӨҡеҗҢеӯҰеңЁиө¶йЎ№зӣ®гҖҒеҒҡиҜҫи®ҫзҡ„ж—¶еҖҷйғҪдјҡжңүиҝҷз§ҚвҖңйҡҸдҫҝз”»зӮ№е•Ҙеҗ§вҖқзҡ„зһ¬й—ҙеҶІеҠЁж„ҹ вҖ”вҖ” жҲ‘жҮӮзҡ„гҖӮ\n\nжүҖд»ҘпјҢж„ҝж„Ҹе’ҢжҲ‘иҜҙиҜҙдҪ зҺ°еңЁзҡ„зңҹе®һжғіжі•еҗ—пјҹдҪ еңЁдёәд»Җд№ҲдәӢзғҰзқҖе‘ўпјҹрҹ’»рҹ’ӯ  \nжҲ‘дјҡеңЁиҝҷйҮҢпјҢе®үйқҷең°еҗ¬дҪ иҜҙгҖӮ','system','2025-12-04 19:59:32','system','2025-12-04 19:59:32',NULL),(125,38,100,1,'жҲ‘еңЁеӯҰд№ Javaд»Јз ҒпјҢдёҚдјҡ','xiaodu','2025-12-04 19:59:40','xiaodu','2025-12-04 19:59:40',NULL),(126,38,100,0,'и°ўи°ўдҪ ж„ҝж„Ҹе’ҢжҲ‘иҜҙиҝҷдәӣгҖӮ\n\n