INSERT INTO `evaluation_result` VALUES (28,3,12,NULL,'й«ҳ','{\"indicators\": {\"sleep_score\": 40, \"social_score\": 55, \"stress_score\": 48, \"anxiety_score\": 45, \"emotion_score\": 47, \"depression_score\": 42, \"self_efficacy_score\": 38}, \"risk_level\": \"й«ҳ\", \"main_issues\": [\"жғ…з»Әи°ғиҠӮиғҪеҠӣиҫғејұ\", \"зқЎзң иҙЁйҮҸжҳҺжҳҫдёӢйҷҚ\", \"иҮӘжҲ‘ж•ҲиғҪж„ҹеҒҸдҪҺ\"], \"suggestions\": [\"е»әз«Ӣи§„еҫӢдҪңжҒҜпјҢзқЎеүҚдёҖе°Ҹж—¶йҒҝе…Қз”өеӯҗи®ҫеӨҮдҪҝз”Ё\", \"жҜҸж—ҘиҝӣиЎҢ10еҲҶй’ҹжӯЈеҝөе‘јеҗёз»ғд№ д»Ҙзј“и§Јз„Ұиҷ‘\", \"и®ҫе®ҡе°ҸиҖҢе…·дҪ“зҡ„жҜҸж—Ҙзӣ®ж Үе№¶и®°еҪ•е®ҢжҲҗжғ…еҶөд»ҘжҸҗеҚҮиҮӘжҲ‘ж•ҲиғҪж„ҹ\", \"дё»еҠЁеҸӮдёҺ1йЎ№дҪҺеҺӢеҠӣзӨҫдәӨжҙ»еҠЁпјҲеҰӮиҜ»д№ҰдјҡгҖҒе…ҙи¶Је°Ҹз»„пјүд»Ҙж”№е–„зӨҫдәӨеҠҹиғҪ\"], \"total_score\": 50, \"detailed_analysis\": \"з”ЁжҲ·еңЁеӨҡйЎ№еҝғзҗҶеҒҘеә·з»ҙеәҰдёҠеҫ—еҲҶеҒҸдҪҺпјҢе°Өе…¶еңЁиҮӘжҲ‘ж•ҲиғҪж„ҹпјҲ38еҲҶпјүе’ҢзқЎзң иҙЁйҮҸпјҲ40еҲҶпјүж–№йқўиЎЁзҺ°жҳҫи‘—дёҚи¶іпјҢжҸҗзӨәеӯҳеңЁжҢҒз»ӯжҖ§иҮӘжҲ‘жҖҖз–‘еҖҫеҗ‘еҸҠз”ҹзҗҶиҠӮеҫӢзҙҠд№ұпјӣз„Ұиҷ‘пјҲ45еҲҶпјүдёҺжҠ‘йғҒпјҲ42еҲҶпјүз»ҙеәҰжҺҘиҝ‘дёҙеәҠе…іжіЁйҳҲеҖјпјҢз»“еҗҲеҺӢеҠӣз»ҙеәҰпјҲ48еҲҶпјүжңӘиҫҫдёҙз•ҢдҪҶе‘ҲеҚҮй«ҳи¶ӢеҠҝпјҢеҸҚжҳ еҪ“еүҚеә”еҜ№иө„жәҗзҙ§еј пјӣзӨҫдәӨеҠҹиғҪзӣёеҜ№иҫғеҘҪпјҲ55еҲҶпјүдҪҶд»ҚдҪҺдәҺеҒҘеә·еҹәеҮҶпјҢиЎЁжҳҺеӯҳеңЁиҪ»еәҰеӣһйҒҝеҖҫеҗ‘гҖӮз»јеҗҲеҲӨж–ӯдёәй«ҳйЈҺйҷ©зҠ¶жҖҒпјҢйңҖдјҳе…Ҳе№Ійў„зқЎзң дёҺиҮӘжҲ‘и®ӨзҹҘжЁЎеқ—гҖӮ\"}','1','1','1','',NULL,'',NULL,NULL),(29,8,12,NULL,NULL,NULL,'0','0','0','',NULL,'',NULL,NULL),(30,3,17,5,'й«ҳ',NULL,'0','1','1','',NULL,'',NULL,NULL),(31,8,17,NULL,NULL,NULL,'0','0','0','',NULL,'',NULL,NULL);
