\":\"2026-02-03 15:11:54\"}','{\"msg\":\"ж“ҚдҪңжҲҗеҠҹ\",\"code\":200}',0,NULL,'2026-02-03 15:11:53',33),(586,'еҝғзҗҶж–Үз« жҺЁиҚҗ',2,'com.mc.recommend.controller.RecommendArticleController.edit()','PUT',1,'admin','иҪҜд»¶е·ҘзЁӢ','/recommend/recommendArticle','127.0.0.1','еҶ…зҪ‘IP','{\"articleId\":3,\"author\":\"иұҶеҢ…еҝғзҗҶ\",\"category\":\"зҲұжғ…\",\"content\":\"# еңЁдәІеҜҶе…ізі»йҮҢпјҢе…Ғи®ёиҮӘе·ұвҖңдёҚе®ҢзҫҺвҖқжүҚжҳҜзңҹжӯЈзҡ„жҲҗзҶҹ\\n\\nжҲ‘д»¬йғҪжӣҫеҜ№зҲұжғ…жңүиҝҮзҫҺеҘҪзҡ„жғіиұЎпјҡеёҢжңӣжүҫеҲ°дёҖдёӘвҖңе®ҢзҫҺвҖқзҡ„дәәпјҢи°ҲдёҖеңәвҖңе®ҢзҫҺвҖқзҡ„жҒӢзҲұпјҢж°ёиҝңдёҚеҗөжһ¶гҖҒдёҚеӨұжңӣгҖҒдёҚеҸ—дјӨгҖӮдҪҶзҺ°е®һжҳҜпјҢжҜҸж®өдәІеҜҶе…ізі»йғҪдјҡйҒҮеҲ°ж‘©ж“ҰпјҢжҜҸдёӘдјҙдҫЈйғҪжңүзјәзӮ№пјҢе°ұиҝһжҲ‘д»¬иҮӘе·ұд№ҹеёёеёёзҠҜй”ҷгҖӮ\\n\\n## дёҖгҖҒвҖңе®ҢзҫҺдё»д№үвҖқжӯЈеңЁжӮ„жӮ„ж¶ҲиҖ—дҪ зҡ„ж„ҹжғ…\\nеҫҲеӨҡдәәеңЁе…ізі»йҮҢд№ жғҜжү®жј”вҖңж»ЎеҲҶйҖүжүӢвҖқпјҡ\\n- дёҚж•ўиЎЁиҫҫзңҹе®һзҡ„йңҖжұӮпјҢжҖ•иў«еҜ№ж–№и§үеҫ—вҖңйә»зғҰвҖқ\\n- еҠӘеҠӣз»ҙжҢҒвҖңжҮӮдәӢвҖқзҡ„еҪўиұЎпјҢе“ӘжҖ•иҮӘе·ұе·Із»Ҹе§”еұҲ\\n- еҜ№дјҙдҫЈзҡ„е°Ҹй”ҷиҜҜиҝҮеәҰж•Ҹж„ҹпјҢжҖ»жғізқҖвҖңд»–еә”иҜҘеҒҡеҫ—жӣҙеҘҪвҖқ\\n\\nиҝҷз§ҚвҖңе®ҢзҫҺж»Өй•ңвҖқдёҚд»…и®©дҪ жҙ»еҫ—еҫҲзҙҜпјҢд№ҹдјҡи®©еҜ№ж–№ж„ҹеҲ°е·ЁеӨ§зҡ„еҺӢеҠӣгҖӮеҪ“дҪ ж— жі•жҺҘеҸ—е…ізі»дёӯзҡ„дёҚе®ҢзҫҺж—¶пјҢе°ҸзҹӣзӣҫеҫҲе®№жҳ“еҚҮзә§жҲҗеӨ§й—®йўҳпјҢжңҖз»ҲжҠҠеҪјжӯӨи¶ҠжҺЁи¶ҠиҝңгҖӮ\\n\\n## дәҢгҖҒзңҹжӯЈзҡ„дәІеҜҶпјҢд»ҺвҖңжҡҙйңІи„ҶејұвҖқејҖе§Ӣ\\nеҘҪзҡ„зҲұжғ…дёҚжҳҜжІЎжңүдәүеҗөпјҢиҖҢжҳҜдәүеҗөеҗҺдҫқз„¶ж„ҝж„ҸжӢҘжҠұпјӣдёҚжҳҜд»ҺдёҚзҠҜй”ҷпјҢиҖҢжҳҜзҠҜй”ҷеҗҺдҫқз„¶йҖүжӢ©дҝЎд»»гҖӮ\\n- **е…Ғи®ёиҮӘе·ұдёҚе®ҢзҫҺ**пјҡжүҝи®ӨиҮӘе·ұдјҡе«үеҰ’гҖҒдјҡеҒ·жҮ’гҖҒдјҡеҒ¶е°”жғ…з»ӘеҢ–пјҢиҝҷдәӣзңҹе®һзҡ„жғ…з»Әе№¶дёҚдјҡз ҙеқҸе…ізі»пјҢеҸҚиҖҢиғҪи®©еҜ№ж–№жӣҙжҮӮдҪ гҖӮ\\n- **е…Ғи®ёеҜ№ж–№дёҚе®ҢзҫҺ**пјҡжҺҘеҸ—д»–жңүдёўдёүиҗҪеӣӣзҡ„е°ҸжҜӣз—…пјҢд№ҹжңүеҒ¶е°”зҡ„жІүй»ҳе’ҢйҖғйҒҝпјҢжІЎжңүдәәеӨ©з”ҹе°ұдјҡзҲұпјҢеӨ§е®¶йғҪеңЁеӯҰд№ дёӯжҲҗй•ҝгҖӮ\\n\\n## дёүгҖҒз”ЁвҖңжҲҗй•ҝеһӢжҖқз»ҙвҖқз»ҸиҗҘе…ізі»\\nжҲҗзҶҹзҡ„дәІеҜҶе…ізі»пјҢдёҚжҳҜвҖңжүҫеҲ°еҜ№зҡ„дәәвҖқпјҢиҖҢжҳҜвҖңжҠҠеҪјжӯӨеҸҳжҲҗеҜ№зҡ„дәәвҖқгҖӮ\\n1. **ж”ҫдёӢжү§еҝө**пјҡеҒңжӯўз”ЁвҖңеә”иҜҘвҖқжқҘиҰҒжұӮеҜ№ж–№пјҢеӨҡй—®вҖңжҲ‘д»¬еҸҜд»ҘдёҖиө·еҒҡдәӣд»Җд№ҲвҖқгҖӮ\\n2. **е°ҸжӯҘдҝ®еӨҚ**пјҡжҜҸж¬ЎзҹӣзӣҫеҗҺпјҢдёҚз”ЁжҖҘзқҖвҖңзҝ»зҜҮвҖқпјҢиҖҢжҳҜдёҖиө·еӨҚзӣҳпјҡвҖңеҲҡжүҚжҲ‘йӮЈж ·иҜҙи®©дҪ дёҚиҲ’жңҚдәҶпјҢдёӢж¬ЎжҲ‘д»¬еҸҜд»ҘиҜ•иҜ•иҝҷж ·жІҹйҖҡвҖҰвҖҰвҖқ\\n3. **ж¬ЈиөҸдёҚе®ҢзҫҺ**пјҡиҜ•зқҖжҠҠеҜ№ж–№зҡ„вҖңзјәзӮ№вҖқзңӢдҪңвҖңзү№зӮ№вҖқпјҢжҜ”еҰӮд»–зҡ„вҖңж…ўеҚҠжӢҚвҖқжҲ–и®ёжӯЈжҳҜд»–зҡ„зЁійҮҚпјҢдҪ зҡ„вҖңзўҺзўҺеҝөвҖқжҲ–и®ёжӯЈжҳҜдҪ зҡ„жё©жҹ”гҖӮ\\n\\n## з»“иҜӯ\\nзҲұжғ…жңҖеҠЁдәәзҡ„ж ·еӯҗпјҢдёҚжҳҜдёӨдёӘе®ҢзҫҺзҡ„дәәеңЁдёҖиө·пјҢиҖҢжҳҜдёӨдёӘдёҚе®ҢзҫҺзҡ„дәәпјҢж„ҝж„ҸдёәдәҶеҪјжӯӨеҸҳеҫ—жӣҙе®Ңж•ҙгҖӮеҪ“дҪ дёҚеҶҚжү§зқҖдәҺвҖңе®ҢзҫҺе…ізі»вҖқпјҢеҸҚиҖҢиғҪеңЁзңҹе®һзҡ„дә’еҠЁйҮҢпјҢж”¶иҺ·жӣҙиёҸе®һзҡ„е№ёзҰҸгҖӮ\",\"createBy\":\"\",\"createTime\":\"2025-11-09 16:45:59\",\"params\":{},\"readCount\":13,\"status\":\"0\",\"summary\":\"жң¬ж–ҮжҺўи®ЁдәҶзҲұжғ…дёӯ вҖңе®ҢзҫҺдё»д№үвҖқ зҡ„йҡҗеҪўдјӨе®іпјҢеҲҶдә«дәҶеҰӮдҪ•ж”ҫдёӢеҜ№ вҖңзҗҶжғідјҙдҫЈвҖқ е’Ң вҖңе®ҢзҫҺе…ізі»вҖқ зҡ„жү§еҝөпјҢйҖҡиҝҮжҺҘзәізңҹе®һзҡ„еҪјжӯӨпјҢе»әз«ӢжӣҙжқҫејӣгҖҒжӣҙй•ҝд№…зҡ„дәІеҜҶе…ізі»гҖӮ\",\"title\":\"гҖҠеңЁдәІеҜҶе…ізі»йҮҢпјҢе…Ғи®ёиҮӘе·ұ вҖңдёҚе®ҢзҫҺвҖқ жүҚжҳҜзңҹжӯЈзҡ„жҲҗзҶҹгҖӢ\",\"updateBy\":\"\",\"updateTime\":\"2026-02-03 15:16:49\"}','{\"msg\":\"ж“ҚдҪңжҲҗеҠҹ\",\"code\":200}',0,NULL,'2026-02-03 15:16:47',40),(587,'её–еӯҗз®ЎзҗҶ',3,'com.mc.community.controller.CommunityPostController.remove()','DELETE',1,'admin','иҪҜд»¶е·ҘзЁӢ','/community/post/14,13,12,11,10,9,8,7,6,5','127.0.0.1','еҶ…зҪ‘IP','[14,13,12,11,10,9,8,7,6,5]','{\"msg\":\"ж“ҚдҪңжҲҗеҠҹ\",\"code\":200}',0,NULL,'2026-02-03 15:33:34',89),(588,'з”ЁжҲ·еӨҙеғҸ',2,'com.mc.web.controller.system.SysProfileController.avatar()','POST',1,'xiaodu','иҪҜд»¶е·ҘзЁӢ','/system/user/profile/avatar','127.0.0.1','еҶ…зҪ‘IP','','{\"msg\":\"ж“ҚдҪңжҲҗеҠҹ\",\"imgUrl\":\"/profile/avatar/2026/02/03/43ea12b8f1934d49992cd1480fcf1880.png\",\"code\":200}',0,NULL,'2026-02-03 15:38:06',34),(589,'её–еӯҗз®ЎзҗҶ',3,'com.mc.community.controller.CommunityPostController.remove()','DELETE',1,'admin','иҪҜд»¶е·ҘзЁӢ','/community/post/16','127.0.0.1','еҶ…зҪ‘IP','[16]','{\"msg\":\"ж“